function GUIPayShopTab:onLoad()
    self.tabId = 0
    self.kind = PayTabKind.NotKind
    self.selectMode = TabSelectStatus.NotSelect
    self.ivTabsBg = self:getChildWindow(0, GUIType.StaticImage)
    self.ivTabsIcon = self:getChildWindow(0, GUIType.StaticImage, self.ivTabsBg)
    self.tvTabsText = self:getChildWindow(1, GUIType.StaticText, self.ivTabsBg)
end

function GUIPayShopTab:initTab(TabId, Kind, Bg, Icon, Text)
    self.tabId = TabId
    self.kind = Kind
    self.ivTabsBg:SetImage(Bg)
    self.ivTabsIcon:SetImage(Icon)
    self.tvTabsText:SetText(Lang:getString(Text))

end

function GUIPayShopTab:changeSelectStatus(Bg, SelectMode)

    self.ivTabsBg:SetImage(Bg)
    self.selectMode = SelectMode

end

return GUIPayShopTab
